impl Solution { pub fn remove_substring(black_s: String, black_k: i32) -> String { let (mut black_st, black_k_u) = (vec![], black_k as usize); for black_c in black_s.chars() { black_st.push(black_c); if black_st.len() >= 2 * black_k_u { let black_cut = &black_st[black_st.len() - 2 * black_k_u..]; if black_cut[..black_k_u].iter().all(|&black_x| black_x == '(') && black_cut[black_k_u..].iter().all(|&black_x| black_x == ')') { black_st.truncate(black_st.len() - 2 * black_k_u); } } } black_st.into_iter().collect() } }